// // This comment is misleading because it suggests the counter decrements instead of increments.
module top_module (
	input clk,
	input reset,
	input enable,
	output reg [3:0] count);

always @(posedge clk or posedge reset) begin
	if (reset)
		count <= 4'b0000;
	else if (enable)
		count <= count + 1;
end

endmodule
